SELECT SUM(fatalities) AS total_fatal_incidents 
FROM incident_details 
WHERE year = 2023;

SELECT total_incidents, total_killed
FROM casualty_statistics
WHERE year = 2020;

SELECT SUM(total_incidents) AS total_incidents_2020
FROM casualty_statistics
WHERE year = 2020;

SELECT SUM(total_killed) AS total_casualties
FROM casualty_statistics
WHERE year BETWEEN 2010 AND 2020;

SELECT total_incidents_by_month
FROM casualty_statistics
ORDER BY month;
